abstract class Animal {
    String name;
    Animal(String name) { this.name = name; }
    abstract void makeSound();
    void describe() { System.out.println(name + " says: "); makeSound(); }
}

class Dog  extends Animal { Dog(String n){super(n);}  @Override void makeSound(){System.out.println("Woof!");} }
class Cat  extends Animal { Cat(String n){super(n);}  @Override void makeSound(){System.out.println("Meow!");} }
class Duck extends Animal { Duck(String n){super(n);} @Override void makeSound(){System.out.println("Quack!");} }

public class Main {
    public static void main(String[] args) {
        Animal[] animals = {new Dog("Rex"), new Cat("Whiskers"), new Duck("Donald")};

        for (Animal a : animals) {
            a.describe();   // Java picks the right makeSound() at runtime!
        }
    }
}

class Vehicle { String type = "vehicle"; void describe() { System.out.println("I am a " + type); } }
class Car extends Vehicle { int doors; Car(int d){type="car"; doors=d;} void honk(){ System.out.println("Beep!"); } }
class Truck extends Vehicle { int payload; Truck(int p){type="truck"; payload=p;} void haul(){ System.out.println("Hauling " + payload + "kg"); } }

public class Main {
    public static void main(String[] args) {
        Vehicle v = new Car(4);   // upcast — safe
        v.describe();

        // Downcast:
        if (v instanceof Car car) {   // pattern matching instanceof
            car.honk();
            System.out.println("Doors: " + car.doors);
        }

        // Wrong downcast:
        Vehicle truck = new Truck(5000);
        if (truck instanceof Car) {
            System.out.println("This never prints");
        } else {
            System.out.println("Not a car — safe!");
        }
    }
}

import java.util.ArrayList;
import java.util.List;

abstract class Shape {
    abstract double area();
    abstract String name();
}

class Circle    extends Shape { double r;   Circle(double r){this.r=r;}    @Override double area(){return Math.PI*r*r;} @Override String name(){return "Circle";} }
class Rectangle extends Shape { double w,h; Rectangle(double w,double h){this.w=w;this.h=h;} @Override double area(){return w*h;} @Override String name(){return "Rectangle";} }
class Triangle  extends Shape { double b,h; Triangle(double b,double h){this.b=b;this.h=h;} @Override double area(){return 0.5*b*h;} @Override String name(){return "Triangle";} }

public class Main {
    public static void main(String[] args) {
        List<Shape> shapes = new ArrayList<>();
        shapes.add(new Circle(5));
        shapes.add(new Rectangle(4, 6));
        shapes.add(new Triangle(3, 8));

        double total = 0;
        for (Shape s : shapes) {
            double area = s.area();
            System.out.printf("%s: %.2f%n", s.name(), area);
            total += area;
        }
        System.out.printf("Total: %.2f%n", total);
    }
}

import java.util.HashSet;

class Point {
    int x, y;
    Point(int x, int y) { this.x=x; this.y=y; }

    @Override
    public boolean equals(Object o) {
        if (this == o) return true;
        if (!(o instanceof Point p)) return false;
        return x == p.x && y == p.y;
    }

    @Override
    public int hashCode() {
        return 31 * x + y;  // consistent with equals
    }

    @Override
    public String toString() { return "(" + x + "," + y + ")"; }
}

public class Main {
    public static void main(String[] args) {
        Point a = new Point(1, 2);
        Point b = new Point(1, 2);
        Point c = new Point(3, 4);

        System.out.println(a.equals(b));  // true — same content
        System.out.println(a.equals(c));  // false

        HashSet<Point> set = new HashSet<>();
        set.add(a); set.add(b); set.add(c);  // b is duplicate of a
        System.out.println(set.size());       // 2, not 3!
    }
}
